     5→
     6→GCC is free software; you can redistribute it and/or modify it under
     7→the terms of the GNU General Public License as published by the Free
     8→Software Foundation; either version 3, or (at your option) any later
     9→version.
    10→
    11→GCC is distributed in the hope that it will be useful, but WITHOUT ANY
    12→WARRANTY; without even the implied warranty of MERCHANTABILITY or
    13→FITNESS FOR A PARTICULAR PURPOSE.  See the GNU General Public License
    14→for more details.
    15→
    16→You should have received a copy of the GNU General Public License
    17→along with GCC; see the file COPYING3.  If not see
    18→<http://www.gnu.org/licenses/>.  */
    19→
    20→/* Note that this file is processed by a simple parser:
    21→   'gen-pass-instances.awk', so carefully verify the generated
    22→   'pass-instances.def' if you deviate from the syntax otherwise used in
    23→   here.  */
    24→
    25→
    26→ /* All passes needed to lower the function into shape optimizers can
    27→    operate on.  These passes are always run first on the function, but
    28→    backend might produce already lowered functions that are not processed
    29→    by these passes.  */
    30→  INSERT_PASSES_AFTER (all_lowering_passes)
    31→  NEXT_PASS (pass_warn_unused_result);
    32→  NEXT_PASS (pass_diagnose_omp_blocks);
    33→  NEXT_PASS (pass_diagnose_tm_blocks);
    34→  NEXT_PASS (pass_omp_oacc_kernels_decompose);
    35→  NEXT_PASS (pass_lower_omp);
    36→  NEXT_PASS (pass_lower_cf);
    37→  NEXT_PASS (pass_lower_tm);
    38→  NEXT_PASS (pass_refactor_eh);
    39→  NEXT_PASS (pass_lower_eh);
    40→  NEXT_PASS (pass_coroutine_lower_builtins);
    41→  NEXT_PASS (pass_build_cfg);
    42→  NEXT_PASS (pass_warn_function_return);
    43→  NEXT_PASS (pass_coroutine_early_expand_ifns);
    44→  NEXT_PASS (pass_expand_omp);
    45→  NEXT_PASS (pass_build_cgraph_edges);
    46→  TERMINATE_PASS_LIST (all_lowering_passes)
    47→
    48→  /* Interprocedural optimization passes.  */
    49→  INSERT_PASSES_AFTER (all_small_ipa_passes)
    50→  /* auto_profile_offline uses dwarf_name hook that only
    51→     works before free_lang_data.  */
    52→  NEXT_PASS (pass_ipa_auto_profile_offline);
    53→  NEXT_PASS (pass_ipa_free_lang_data);
    54→  NEXT_PASS (pass_ipa_function_and_variable_visibility);
    55→  NEXT_PASS (pass_ipa_strub_mode);
    56→  NEXT_PASS (pass_build_ssa_passes);
    57→  PUSH_INSERT_PASSES_WITHIN (pass_build_ssa_passes)
    58→      NEXT_PASS (pass_fixup_cfg);
    59→      NEXT_PASS (pass_build_ssa);
    60→      NEXT_PASS (pass_walloca, /*strict_mode_p=*/true);
    61→      NEXT_PASS (pass_warn_printf);
    62→      NEXT_PASS (pass_warn_nonnull_compare);
    63→      NEXT_PASS (pass_early_warn_uninitialized);
    64→      NEXT_PASS (pass_warn_access, /*early=*/true, /*check_dangling=*/true);
    65→      NEXT_PASS (pass_ubsan);
    66→      NEXT_PASS (pass_nothrow);
    67→      NEXT_PASS (pass_rebuild_cgraph_edges);
    68→  POP_INSERT_PASSES ()
    69→  NEXT_PASS (pass_target_clone, true);
    70→
    71→  NEXT_PASS (pass_local_optimization_passes);
    72→  PUSH_INSERT_PASSES_WITHIN (pass_local_optimization_passes)
    73→      NEXT_PASS (pass_fixup_cfg);
    74→      NEXT_PASS (pass_rebuild_cgraph_edges);
    75→      NEXT_PASS (pass_local_fn_summary);
    76→      NEXT_PASS (pass_early_inline);
    77→      NEXT_PASS (pass_warn_recursion);
    78→      NEXT_PASS (pass_all_early_optimizations);
    79→      PUSH_INSERT_PASSES_WITHIN (pass_all_early_optimizations)
    80→	  NEXT_PASS (pass_remove_cgraph_callee_edges);
    81→	  NEXT_PASS (pass_early_object_sizes);
    82→	  /* Don't record nonzero bits before IPA to avoid
    83→	     using too much memory.  */
    84→	  NEXT_PASS (pass_ccp, false /* nonzero_p */);
    85→	  /* After CCP we rewrite no longer addressed locals into SSA
    86→	     form if possible.  */
    87→	  NEXT_PASS (pass_forwprop, /*full_walk=*/true);
    88→          NEXT_PASS (pass_early_thread_jumps, /*first=*/true);
    89→	  NEXT_PASS (pass_sra_early);
    90→	  /* pass_build_ealias is a dummy pass that ensures that we
    91→	     execute TODO_rebuild_alias at this point.  */
    92→	  NEXT_PASS (pass_build_ealias);
    93→	  /* Do phiprop before FRE so we optimize std::min and std::max well.  */
    94→	  NEXT_PASS (pass_phiprop);
    95→	  NEXT_PASS (pass_fre, true /* may_iterate */);
    96→	  NEXT_PASS (pass_early_vrp);
    97→	  NEXT_PASS (pass_merge_phi);
    98→          NEXT_PASS (pass_dse);
    99→	  NEXT_PASS (pass_cd_dce, false /* update_address_taken_p */, true /* remove_unused_locals */);
   100→	  NEXT_PASS (pass_phiopt, true /* early_p */);
   101→	  /* Cleanup eh is done before tail recusision to remove empty (only clobbers)
   102→	     finally blocks which would block tail recursion.  */
   103→	  NEXT_PASS (pass_cleanup_eh);
   104→	  NEXT_PASS (pass_tail_recursion);
   105→	  NEXT_PASS (pass_if_to_switch);
   106→	  NEXT_PASS (pass_convert_switch);
   107→	  NEXT_PASS (pass_sccopy);
   108→	  NEXT_PASS (pass_profile);
   109→	  NEXT_PASS (pass_local_pure_const);
   110→	  NEXT_PASS (pass_modref);
   111→	  /* Split functions creates parts that are not run through
   112→	     early optimizations again.  It is thus good idea to do this
   113→	      late.  */
   114→	  NEXT_PASS (pass_split_functions);
   115→	  NEXT_PASS (pass_strip_predict_hints, true /* early_p */);
   116→      POP_INSERT_PASSES ()
   117→      NEXT_PASS (pass_release_ssa_names);
   118→      NEXT_PASS (pass_rebuild_cgraph_edges);
   119→      NEXT_PASS (pass_local_fn_summary);
   120→  POP_INSERT_PASSES ()
   121→
   122→  NEXT_PASS (pass_ipa_remove_symbols);
   123→  NEXT_PASS (pass_ipa_strub);
   124→  NEXT_PASS (pass_ipa_oacc);
   125→  PUSH_INSERT_PASSES_WITHIN (pass_ipa_oacc)
   126→      NEXT_PASS (pass_ipa_pta);
   127→      /* Pass group that runs when the function is an offloaded function
   128→	 containing oacc kernels loops.	 */
   129→      NEXT_PASS (pass_ipa_oacc_kernels);
   130→      PUSH_INSERT_PASSES_WITHIN (pass_ipa_oacc_kernels)
   131→	  NEXT_PASS (pass_oacc_kernels);
   132→	  PUSH_INSERT_PASSES_WITHIN (pass_oacc_kernels)
   133→	      NEXT_PASS (pass_ch);
   134→	      NEXT_PASS (pass_fre, true /* may_iterate */);
   135→	      /* We use pass_lim to rewrite in-memory iteration and reduction
   136→		 variable accesses in loops into local variables accesses.  */
   137→	      NEXT_PASS (pass_lim);
   138→	      NEXT_PASS (pass_dominator, false /* may_peel_loop_headers_p */);
   139→	      NEXT_PASS (pass_dce);
   140→	      NEXT_PASS (pass_parallelize_loops, true /* oacc_kernels_p */);
   141→	      NEXT_PASS (pass_expand_omp_ssa);
   142→	      NEXT_PASS (pass_rebuild_cgraph_edges);
   143→	  POP_INSERT_PASSES ()
   144→      POP_INSERT_PASSES ()
   145→  POP_INSERT_PASSES ()
   146→
   147→  NEXT_PASS (pass_target_clone, false);
   148→  NEXT_PASS (pass_ipa_auto_profile);
   149→  PUSH_INSERT_PASSES_WITHIN (pass_ipa_auto_profile)
   150→      NEXT_PASS (pass_feedback_split_functions);
   151→  POP_INSERT_PASSES ()
   152→  NEXT_PASS (pass_ipa_tree_profile);
   153→  PUSH_INSERT_PASSES_WITHIN (pass_ipa_tree_profile)
   154→      NEXT_PASS (pass_feedback_split_functions);
   155→  POP_INSERT_PASSES ()
   156→  NEXT_PASS (pass_ipa_free_fn_summary, true /* small_p */);
   157→  NEXT_PASS (pass_ipa_increase_alignment);
   158→  NEXT_PASS (pass_ipa_tm);
   159→  NEXT_PASS (pass_ipa_lower_emutls);
   160→  NEXT_PASS (pass_ipa_asm_lgen);
   161→  TERMINATE_PASS_LIST (all_small_ipa_passes)
   162→
   163→  INSERT_PASSES_AFTER (all_regular_ipa_passes)
   164→  NEXT_PASS (pass_analyzer);
   165→  NEXT_PASS (pass_ipa_asm_wpa);
   166→  NEXT_PASS (pass_ipa_odr);
   167→  NEXT_PASS (pass_ipa_whole_program_visibility);
   168→  NEXT_PASS (pass_ipa_profile);
   169→  NEXT_PASS (pass_ipa_icf);
   170→  NEXT_PASS (pass_ipa_devirt);
   171→  NEXT_PASS (pass_ipa_cdtor_merge);
   172→  NEXT_PASS (pass_ipa_cp);
   173→  NEXT_PASS (pass_ipa_sra);
   174→  NEXT_PASS (pass_ipa_fn_summary);
   175→  NEXT_PASS (pass_ipa_inline);
   176→  NEXT_PASS (pass_ipa_locality_cloning);
   177→  NEXT_PASS (pass_ipa_pure_const);
   178→  NEXT_PASS (pass_ipa_modref);
   179→  NEXT_PASS (pass_ipa_free_fn_summary, false /* small_p */);
   180→  NEXT_PASS (pass_ipa_reference);
   181→  /* This pass needs to be scheduled after any IP code duplication.   */
   182→  NEXT_PASS (pass_ipa_single_use);
   183→  /* Comdat privatization come last, as direct references to comdat local
   184→     symbols are not allowed outside of the comdat group.  Privatizing early
   185→     would result in missed optimizations due to this restriction.  */
   186→  NEXT_PASS (pass_ipa_comdats);
   187→  TERMINATE_PASS_LIST (all_regular_ipa_passes)
   188→
   189→  /* Simple IPA passes executed after the regular passes.  In WHOPR mode the
   190→     passes are executed after partitioning and thus see just parts of the
   191→     compiled unit.  */
   192→  INSERT_PASSES_AFTER (all_late_ipa_passes)
   193→  NEXT_PASS (pass_ipa_pta);
   194→  NEXT_PASS (pass_omp_simd_clone);
   195→  TERMINATE_PASS_LIST (all_late_ipa_passes)
   196→
   197→  /* These passes are run after IPA passes on every function that is being
   198→     output to the assembler file.  */
   199→  INSERT_PASSES_AFTER (all_passes)
   200→  NEXT_PASS (pass_fixup_cfg);
   201→  NEXT_PASS (pass_lower_eh_dispatch);
   202→  NEXT_PASS (pass_oacc_loop_designation);
   203→  NEXT_PASS (pass_omp_oacc_neuter_broadcast);
   204→  NEXT_PASS (pass_oacc_device_lower);
   205→  NEXT_PASS (pass_omp_device_lower);
   206→  NEXT_PASS (pass_omp_target_link);
   207→  NEXT_PASS (pass_adjust_alignment);
   208→  NEXT_PASS (pass_harden_control_flow_redundancy);
   209→  NEXT_PASS (pass_all_optimizations);
   210→  PUSH_INSERT_PASSES_WITHIN (pass_all_optimizations)
   211→      NEXT_PASS (pass_remove_cgraph_callee_edges);
   212→      /* Initial scalar cleanups before alias computation.
   213→	 They ensure memory accesses are not indirect wherever possible.  */
   214→      NEXT_PASS (pass_strip_predict_hints, false /* early_p */);
   215→      NEXT_PASS (pass_ccp, true /* nonzero_p */);
   216→      /* After CCP we rewrite no longer addressed locals into SSA
   217→	 form if possible.  */
   218→      NEXT_PASS (pass_object_sizes);
   219→      NEXT_PASS (pass_post_ipa_warn);
   220→      /* Must run before loop unrolling.  */
   221→      NEXT_PASS (pass_warn_access, /*early=*/false, /*check_dangling=*/true);
   222→      /* Profile count may overflow as a result of inlinining very large
   223→         loop nests.  This pass should run before any late pass that makes
   224→	 use of profile.  */
   225→      NEXT_PASS (pass_rebuild_frequencies);
   226→      NEXT_PASS (pass_complete_unrolli);
   227→      NEXT_PASS (pass_backprop);
   228→      NEXT_PASS (pass_phiprop);
   229→      NEXT_PASS (pass_forwprop, /*full_walk=*/true);
   230→      /* pass_build_alias is a dummy pass that ensures that we
   231→	 execute TODO_rebuild_alias at this point.  */
   232→      NEXT_PASS (pass_build_alias);
   233→      NEXT_PASS (pass_return_slot);
   234→      NEXT_PASS (pass_fre, true /* may_iterate */);
   235→      NEXT_PASS (pass_merge_phi);
   236→      NEXT_PASS (pass_thread_jumps_full, /*first=*/true);
   237→      NEXT_PASS (pass_vrp, false /* final_p*/);
   238→      NEXT_PASS (pass_array_bounds);
   239→      NEXT_PASS (pass_dse);
   240→      NEXT_PASS (pass_dce, false /* update_address_taken_p */, true /* remove_unused_locals */);
   241→      NEXT_PASS (pass_stdarg);
   242→      NEXT_PASS (pass_call_cdce);
   243→      NEXT_PASS (pass_cselim);
   244→      NEXT_PASS (pass_copy_prop);
   245→      NEXT_PASS (pass_tree_ifcombine);
   246→      NEXT_PASS (pass_merge_phi);
   247→      NEXT_PASS (pass_phiopt, false /* early_p */);
   248→      NEXT_PASS (pass_tail_recursion);
   249→      NEXT_PASS (pass_ch);
   250→      NEXT_PASS (pass_lower_complex);
   251→      NEXT_PASS (pass_lower_bitint);
   252→      NEXT_PASS (pass_sra);
   253→      /* The dom pass will also resolve all __builtin_constant_p calls
   254→         that are still there to 0.  This has to be done after some
   255→	 propagations have already run, but before some more dead code
   256→	 is removed, and this place fits nicely.  Remember this when
   257→	 trying to move or duplicate pass_dominator somewhere earlier.  */
   258→      NEXT_PASS (pass_thread_jumps, /*first=*/true);
   259→      NEXT_PASS (pass_dominator, true /* may_peel_loop_headers_p */);
   260→      /* Threading can leave many const/copy propagations in the IL.
   261→	 Clean them up.  Failure to do so well can lead to false
   262→	 positives from warnings for erroneous code.  */
   263→      NEXT_PASS (pass_copy_prop);
   264→      /* Identify paths that should never be executed in a conforming
   265→	 program and isolate those paths.  */
   266→      NEXT_PASS (pass_isolate_erroneous_paths);
   267→      NEXT_PASS (pass_reassoc, true /* early_p */);
   268→      NEXT_PASS (pass_dce);
   269→      NEXT_PASS (pass_forwprop);
   270→      NEXT_PASS (pass_phiopt, false /* early_p */);
   271→      NEXT_PASS (pass_ccp, true /* nonzero_p */);
   272→      /* After CCP we rewrite no longer addressed locals into SSA
   273→	 form if possible.  */
   274→      NEXT_PASS (pass_expand_pow);
   275→      NEXT_PASS (pass_optimize_bswap);
   276→      NEXT_PASS (pass_laddress);
   277→      NEXT_PASS (pass_lim);
   278→      NEXT_PASS (pass_walloca, false);
   279→      NEXT_PASS (pass_pre);
   280→      NEXT_PASS (pass_sink_code, false /* unsplit edges */);
   281→      NEXT_PASS (pass_sancov);
   282→      NEXT_PASS (pass_asan);
   283→      NEXT_PASS (pass_tsan);
   284→      NEXT_PASS (pass_dse, true /* use DR analysis */);
   285→      NEXT_PASS (pass_dce, false /* update_address_taken_p */, false /* remove_unused_locals */);
   286→      /* Pass group that runs when 1) enabled, 2) there are loops
   287→	 in the function.  Make sure to run pass_fix_loops before
   288→	 to discover/remove loops before running the gate function
   289→	 of pass_tree_loop.  */
   290→      NEXT_PASS (pass_fix_loops);
   291→      NEXT_PASS (pass_tree_loop);
   292→      PUSH_INSERT_PASSES_WITHIN (pass_tree_loop)
   293→          /* Before loop_init we rewrite no longer addressed locals into SSA
   294→	     form if possible.  */
   295→	  NEXT_PASS (pass_tree_loop_init);
   296→	  NEXT_PASS (pass_tree_unswitch);
   297→	  NEXT_PASS (pass_loop_split);
   298→	  NEXT_PASS (pass_scev_cprop);
   299→	  NEXT_PASS (pass_loop_versioning);
   300→	  NEXT_PASS (pass_loop_jam);
   301→	  /* All unswitching, final value replacement and splitting can expose
   302→	     empty loops.  Remove them now.  */
   303→	  NEXT_PASS (pass_cd_dce, false /* update_address_taken_p */);
   304→	  NEXT_PASS (pass_iv_canon);
   305→	  NEXT_PASS (pass_loop_distribution);
   306→	  NEXT_PASS (pass_crc_optimization);
   307→	  NEXT_PASS (pass_linterchange);
   308→	  NEXT_PASS (pass_copy_prop);
   309→	  NEXT_PASS (pass_graphite);
   310→	  PUSH_INSERT_PASSES_WITHIN (pass_graphite)
   311→	      NEXT_PASS (pass_graphite_transforms);
   312→	      NEXT_PASS (pass_lim);
   313→	      NEXT_PASS (pass_copy_prop);
   314→	      NEXT_PASS (pass_dce);
   315→	  POP_INSERT_PASSES ()
   316→	  NEXT_PASS (pass_parallelize_loops, false /* oacc_kernels_p */);
   317→	  NEXT_PASS (pass_expand_omp_ssa);
   318→	  NEXT_PASS (pass_ch_vect);
   319→	  NEXT_PASS (pass_if_conversion);
   320→	  /* pass_vectorize must immediately follow pass_if_conversion.
   321→	     Please do not add any other passes in between.  */
   322→	  NEXT_PASS (pass_vectorize);
   323→	  PUSH_INSERT_PASSES_WITHIN (pass_vectorize)
   324→	      NEXT_PASS (pass_dce);
   325→	  POP_INSERT_PASSES ()
   326→	  NEXT_PASS (pass_predcom);
   327→	  NEXT_PASS (pass_complete_unroll);
   328→	  NEXT_PASS (pass_pre_slp_scalar_cleanup);
   329→	  PUSH_INSERT_PASSES_WITHIN (pass_pre_slp_scalar_cleanup)
   330→	      NEXT_PASS (pass_fre, false /* may_iterate */);
   331→	      NEXT_PASS (pass_dse);
   332→	  POP_INSERT_PASSES ()
   333→	  NEXT_PASS (pass_slp_vectorize);
   334→	  NEXT_PASS (pass_loop_prefetch);
   335→	  /* Run IVOPTs after the last pass that uses data-reference analysis
   336→	     as that doesn't handle TARGET_MEM_REFs.  */
   337→	  NEXT_PASS (pass_iv_optimize);
   338→	  NEXT_PASS (pass_lim);
   339→	  NEXT_PASS (pass_tree_loop_done);
   340→      POP_INSERT_PASSES ()
   341→      /* Pass group that runs when pass_tree_loop is disabled or there
   342→         are no loops in the function.  */
   343→      NEXT_PASS (pass_tree_no_loop);
   344→      PUSH_INSERT_PASSES_WITHIN (pass_tree_no_loop)
   345→	  NEXT_PASS (pass_slp_vectorize);
   346→      POP_INSERT_PASSES ()
   347→      NEXT_PASS (pass_simduid_cleanup);
   348→      NEXT_PASS (pass_lower_vector_ssa);
   349→      NEXT_PASS (pass_lower_switch);
   350→      NEXT_PASS (pass_cse_sincos);
   351→      NEXT_PASS (pass_cse_reciprocals);
   352→      NEXT_PASS (pass_reassoc, false /* early_p */);
   353→      NEXT_PASS (pass_strength_reduction);
   354→      NEXT_PASS (pass_split_paths);
   355→      NEXT_PASS (pass_tracer);
   356→      NEXT_PASS (pass_fre, false /* may_iterate */);
   357→      /* After late FRE we rewrite no longer addressed locals into SSA
   358→         form if possible.  */
   359→      NEXT_PASS (pass_thread_jumps, /*first=*/false);
   360→      NEXT_PASS (pass_dominator, false /* may_peel_loop_headers_p */);
   361→      NEXT_PASS (pass_strlen);
   362→      NEXT_PASS (pass_thread_jumps_full, /*first=*/false);
   363→      NEXT_PASS (pass_vrp, true /* final_p */);
   364→      /* Run CCP to compute alignment and nonzero bits.  */
   365→      NEXT_PASS (pass_ccp, true /* nonzero_p */);
   366→      NEXT_PASS (pass_warn_restrict);
   367→      NEXT_PASS (pass_dse);
   368→      NEXT_PASS (pass_dce, true /* update_address_taken_p */, true /* remove_unused_locals */);
   369→      /* After late DCE we rewrite no longer addressed locals into SSA
   370→	 form if possible.  */
   371→      NEXT_PASS (pass_forwprop, /*full_walk=*/false, /*last=*/true);
   372→      NEXT_PASS (pass_sink_code, true /* unsplit edges */);
   373→      NEXT_PASS (pass_phiopt, false /* early_p */);
   374→      NEXT_PASS (pass_optimize_widening_mul);
   375→      NEXT_PASS (pass_store_merging);
   376→      /* If DCE is not run before checking for uninitialized uses,
   377→	 we may get false warnings (e.g., testsuite/gcc.dg/uninit-5.c).
   378→	 However, this also causes us to misdiagnose cases that should be
   379→	 real warnings (e.g., testsuite/gcc.dg/pr18501.c).  */
   380→      NEXT_PASS (pass_cd_dce, false /* update_address_taken_p */);
   381→      NEXT_PASS (pass_sccopy);
   382→      NEXT_PASS (pass_tail_calls);
   383→      /* Split critical edges before late uninit warning to reduce the
   384→         number of false positives from it.  */
   385→      NEXT_PASS (pass_split_crit_edges);
   386→      NEXT_PASS (pass_late_warn_uninitialized);
   387→      NEXT_PASS (pass_local_pure_const);
   388→      NEXT_PASS (pass_modref);
   389→      /* uncprop replaces constants by SSA names.  This makes analysis harder
   390→	 and thus it should be run last.  */
   391→      NEXT_PASS (pass_uncprop);
   392→  POP_INSERT_PASSES ()
   393→  NEXT_PASS (pass_all_optimizations_g);
   394→  PUSH_INSERT_PASSES_WITHIN (pass_all_optimizations_g)
   395→      /* The idea is that with -Og we do not perform any IPA optimization
   396→	 so post-IPA work should be restricted to semantically required
   397→	 passes and all optimization work is done early.  */
   398→      NEXT_PASS (pass_remove_cgraph_callee_edges);
   399→      NEXT_PASS (pass_strip_predict_hints, false /* early_p */);
   400→      /* Lower remaining pieces of GIMPLE.  */
   401→      NEXT_PASS (pass_lower_complex);
   402→      NEXT_PASS (pass_lower_bitint);
   403→      NEXT_PASS (pass_lower_vector_ssa);
   404→      NEXT_PASS (pass_lower_switch);
   405→      /* Perform simple scalar cleanup which is constant/copy propagation.  */
   406→      NEXT_PASS (pass_ccp, true /* nonzero_p */);
   407→      NEXT_PASS (pass_post_ipa_warn);
   408→      NEXT_PASS (pass_object_sizes);
   409→      NEXT_PASS (pass_strlen);
   410→      /* Fold remaining builtins.  */
   411→      NEXT_PASS (pass_forwprop, /*full_walk=*/false, /*last=*/true);
   412→      NEXT_PASS (pass_dce);
   413→      /* Profile count may overflow as a result of inlinining very large
   414→         loop nests.  This pass should run before any late pass that makes
   415→	 use of profile.  */
   416→      NEXT_PASS (pass_rebuild_frequencies);
   417→      NEXT_PASS (pass_sancov);
   418→      NEXT_PASS (pass_asan);
   419→      NEXT_PASS (pass_tsan);
   420→      /* ???  We do want some kind of loop invariant motion, but we possibly
   421→         need to adjust LIM to be more friendly towards preserving accurate
   422→	 debug information here.  */
   423→      /* Split critical edges before late uninit warning to reduce the
   424→         number of false positives from it.  */
   425→      NEXT_PASS (pass_split_crit_edges);
   426→      NEXT_PASS (pass_late_warn_uninitialized);
   427→      /* uncprop replaces constants by SSA names.  This makes analysis harder
   428→	 and thus it should be run last.  */
   429→      NEXT_PASS (pass_uncprop);
   430→  POP_INSERT_PASSES ()
   431→  NEXT_PASS (pass_assumptions);
   432→  NEXT_PASS (pass_tm_init);
   433→  PUSH_INSERT_PASSES_WITHIN (pass_tm_init)
   434→      NEXT_PASS (pass_tm_mark);
   435→      NEXT_PASS (pass_tm_memopt);
   436→      NEXT_PASS (pass_tm_edges);
   437→  POP_INSERT_PASSES ()
   438→  NEXT_PASS (pass_simduid_cleanup);
